tasks.pseudocode:
DetailScreen.OnVisible:
  Set(req, LookUp(gt_graphicrequest, gt_graphicrequestid = Param.req.gt_graphicrequestid))

lblGcn.Text = req.gt_graphiccontrolnumber  // bound, no input control
drpStatus.Items = ['Pending','In Progress','Completed']
drpStatus.Default = req.gt_status
tglEmailEdit.Default = req.gt_emailtoauthor

btnSave.OnSelect:
  Patch(gt_graphicrequest, req, {
    gt_status: drpStatus.Selected.Value,
    gt_emailtoauthor: tglEmailEdit.Value
  });
  Notify('Saved', NotificationType.Success);
  Back()
